<?php
namespace App\Services\Localization;
class LocaleManager{public function supportedLocales():array{return config('bikube_locales.supported',[]);}public function defaultLocale():string{return config('bikube_locales.default','nb');}public function fallbackLocale():string{return config('bikube_locales.fallback','en');}public function isSupported(?string $locale):bool{return is_string($locale)&&array_key_exists($locale,$this->supportedLocales());}public function setLocale(string $locale):string{$locale=$this->isSupported($locale)?$locale:$this->defaultLocale();app()->setLocale($locale);return $locale;}public function currentLocale():string{return app()->getLocale();}public function localeDisplayName(string $locale):string{return $this->supportedLocales()[$locale]??$locale;}}
